using NP std;
NP phigrOS
{
	il ll read()
	{
		ll x=0,f=1;char ch=gc();
		wh(ch<'0'||ch>'9'){if(ch=='-')f=-1;ch=getchar();}
		wh(ch>='0'&&ch<='9'){x=x*10+ch-'0';ch=gc();}
		return x*f;
	}
	void write(ll x)
	{
		if(x<0)pc('-'),x=-x;
		if(x>9)write(x/10);
		pc(x%10+'0');
	}
	void writeln(ll x)
	{
		write(x);
		puts("");
		return;
	}
}
using NP phigrOS;
CI MAXN=2e5+5;
struct node
{
	int x,y,e;
	bool operator<(const node&b)const
    {
		return e>b.e;
	}
}a[MAXN];
int f[MAXN];
map<int,int>mp;
int find(int x)
{
	if(x==f[x])return x;
	return f[x]=find(f[x]);
}
signed main(void)
{
	ROF(t,read(),1)
    {
		int n=read(),id=0,flag=0;
		mp.clear();
        FOR(i,1,2*n)f[i]=i;
		FOR(i,1,n)
        {
			a[i].x=read();
			a[i].y=read();
			a[i].e=read();
		}
		sort(a+1,a+n+1);
		FOR(i,1,n)
        {
			if(!mp[a[i].x])mp[a[i].x]=++id;
			if(!mp[a[i].y])mp[a[i].y]=++id;
			int u=mp[a[i].x],v=mp[a[i].y];
			int ru=find(u),rv=find(v);
			if(a[i].e)
            {
				if(ru!=rv)f[ru]=rv;
			}
            else
            {
				if(ru==rv)
                {
					puts("NO");
					flag=1;
					break;
				}
			}
		}
		if(!flag)puts("YES");
		FOR(i,1,id)f[i]=i;
	}
	return false;
}
